import React from 'react';
import { useAuth } from '../../contexts/AuthContext';

const TestAdmin = () => {
  const { user, isAuthenticated, isAdmin } = useAuth();

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-2xl font-bold text-gray-900 mb-6">管理员权限测试</h1>

        <div className="bg-white rounded-xl shadow-sm p-6">
          <div className="space-y-4">
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-2">认证状态</h3>
              <div className="space-y-2">
                <p><strong>登录状态:</strong> {isAuthenticated ? '已登录' : '未登录'}</p>
                <p><strong>用户角色:</strong> {user?.role || '未知'}</p>
                <p><strong>是否管理员:</strong> {isAdmin() ? '是' : '否'}</p>
                <p><strong>用户名:</strong> {user?.username || '未知'}</p>
              </div>
            </div>

            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-2">测试结果</h3>
              <div className={`p-4 rounded-lg ${isAuthenticated && isAdmin() ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'}`}>
                {isAuthenticated && isAdmin() ? (
                  <p>✅ 管理员权限验证通过</p>
                ) : (
                  <p>❌ 管理员权限验证失败</p>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TestAdmin;
